INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-814ced5a-moex-00398', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '除圖書之外，圖書館館藏也包括錄音、錄影資料。根據《中國編目規則》第三版，錄音、電影及錄影資 料書目紀錄的建置，下列敘述何者正確？', '["錄音、電影及錄影資料依據第七章視聽資料，其他靜態視聽型資料依照靜畫資料專章處理", "電影片及錄影資料的主要著錄來源，依次為影帶片本身、不可分離的盛裝物及其標籤", "電影片及錄影資料之捲數、張數或其他單位以國字計其數量", "錄音資料、電影與錄影資料若具正題名與並列題名，「資料類型標示」應著錄於正題名與並列題名之後"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00399', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '書名頁同時載有作品之共同題名及個別題名，依據《中國編目規則》第三版應如何著錄？', '["以共同題名為正題名，個別題名為副題名（個別題名間以逗號區隔）", "以個別題名為正題名（個別題名間以逗號區隔），共同題名為並列題名", "以第一個個別題名為正題名，其他個別題名為並列題名，共同題名記於集叢項", "以共同題名為正題名，個別題名記於附註項內容註"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00400', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '依據《中國編目規則》第三版，有關稽核項面頁數著錄之說明，下列敘述何者正確？', '["[8],219,[41]面 正文前加總後8葉，正文219葉，正文後加總之後41面", "[115]葉 頁數加總後共計115面", "2,315面, 圖版9葉 正文2315面，圖版9葉", "5,123+ 面 正文前5面，正文不只123面，第123面以後的頁面佚去"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00401', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '依據《資源描述與檢索》（RDA），若資源包括動態影像，下列何者為其首選著錄來源？', '["載有題名畫面", "封面或封套標籤", "附隨資料版權頁題名", "資源本身載有題名的標籤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00402', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '整合性資源採用《資源描述與檢索》（ResourceDescription&Access,RDA）進行編目時，下列何種情況 不需要另外建立一筆書目？', '["發行模式改變", "媒體特性改變", "版本敘述改變", "副題名改變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00403', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '作家柯景騰以其筆名「九把刀」創作小說，依據《資源描述與檢索》（RDA）採用九把刀為個人首選名 稱，下列敘述何者錯誤？', '["作者筆名最為著稱", "作者未曾使用真名創作", "作者個人僅使用一個筆名", "小說家必須以筆名為首選名稱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00404', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '關於「權威檢索點」之敘述，下列何者正確？', '["權威檢索點在RDA中是被定義為可用以檢索並代表一個作品、表現形式、個人、家族或團體等實體的 標準檢索點形式", "透過著錄一個具體呈現或單件的權威檢索點，可將創作者、作品及表現形式的首選名稱或重要識別特 性，在書目紀錄中做組合呈現", "在主要關係表述上，目前主要用於具體呈現及單件的識別與描述", "權威檢索點等同於AACR2的主要款目（mainentry）概念"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00405', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '關於杜威十進分類法之敘述，下列何者錯誤？', '["1876年問世", "2011年出版至第23版", "1993年首次推出DOS光碟版", "第15版首度冠上Dewey的名稱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "40fc77b37f2d", "answer_pdf_sha1": "de904699258a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
